import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

type AppearanceMode = "light" | "dark" | "system";

interface ThemeSnapshot {
  appearance: AppearanceMode;
  systemDark: boolean;
  colorThemeId: string;
}

// ---------------------------------------------------------------------------
// Storage keys
// ---------------------------------------------------------------------------

const APPEARANCE_KEY = "t3code:theme";
const COLOR_THEME_KEY = "t3code:color-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// Module-level reactive state (shared across all hook instances)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredAppearance(): AppearanceMode {
  const raw = localStorage.getItem(APPEARANCE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredColorThemeId(): string {
  return localStorage.getItem(COLOR_THEME_KEY) ?? DEFAULT_THEME_ID;
}

// ---------------------------------------------------------------------------
// DOM side-effects
// ---------------------------------------------------------------------------

function applyAppearance(mode: AppearanceMode, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = mode === "dark" || (mode === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function applyColorTheme(themeId: string) {
  const theme = getTheme(themeId);
  if (!theme) return;

  const root = document.documentElement;
  root.style.setProperty("--theme-background", theme.colors.background);
  root.style.setProperty("--theme-foreground", theme.colors.foreground);
  root.style.setProperty("--theme-accent", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);
}

// Apply immediately on module load to prevent flash
applyAppearance(getStoredAppearance());
applyColorTheme(getStoredColorThemeId());

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const appearance = getStoredAppearance();
  const systemDark = appearance === "system" ? getSystemDark() : false;
  const colorThemeId = getStoredColorThemeId();

  if (
    lastSnapshot &&
    lastSnapshot.appearance === appearance &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.colorThemeId === colorThemeId
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { appearance, systemDark, colorThemeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredAppearance() === "system") applyAppearance("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === APPEARANCE_KEY) {
      applyAppearance(getStoredAppearance(), true);
      emitChange();
    }
    if (e.key === COLOR_THEME_KEY) {
      applyColorTheme(getStoredColorThemeId());
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" =
    snapshot.appearance === "system"
      ? snapshot.systemDark
        ? "dark"
        : "light"
      : snapshot.appearance;

  // Appearance mode (light / dark / system) — back-compat name
  const theme = snapshot.appearance;

  const setTheme = useCallback((next: AppearanceMode) => {
    localStorage.setItem(APPEARANCE_KEY, next);
    applyAppearance(next, true);
    emitChange();
  }, []);

  // Color theme (t3-dark, t3-light, t3-midnight, etc.)
  const colorThemeId = snapshot.colorThemeId;
  const colorTheme: Theme | undefined = getTheme(colorThemeId);
  const availableThemes: readonly Theme[] = listThemes();

  const setColorTheme = useCallback((id: string) => {
    localStorage.setItem(COLOR_THEME_KEY, id);
    applyColorTheme(id);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyAppearance(snapshot.appearance);
  }, [snapshot.appearance]);

  useEffect(() => {
    applyColorTheme(snapshot.colorThemeId);
  }, [snapshot.colorThemeId]);

  return {
    /** Current appearance preference ("light" | "dark" | "system"). */
    theme,
    /** Set the appearance preference. */
    setTheme,
    /** Resolved appearance after evaluating "system". */
    resolvedTheme,
    /** Currently active color theme definition. */
    colorTheme,
    /** Id of the active color theme. */
    colorThemeId,
    /** Set the active color theme by id. */
    setColorTheme,
    /** All available color themes. */
    availableThemes,
  } as const;
}

