import type { Theme } from "@t3tools/shared/themes";
import { CheckIcon } from "lucide-react";

import { useTheme } from "~/hooks/useTheme";

/** Small color swatch showing the five most distinctive palette colors. */
function ThemeSwatch({ theme }: { theme: Theme }) {
  const { colors } = theme;
  const swatchColors = [
    colors.background,
    colors.sidebar,
    colors.accent,
    colors.foreground,
    colors.editor,
  ];

  return (
    <div className="flex gap-0.5">
      {swatchColors.map((color, i) => (
        <span
          key={i}
          className="size-3 rounded-full border border-border/40"
          style={{ backgroundColor: color }}
        />
      ))}
    </div>
  );
}

/**
 * Renders a list of available color themes with preview swatches.
 * The currently-active theme is visually highlighted.
 */
export function ThemeSelector() {
  const { colorThemeId, setColorTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((theme) => {
        const selected = colorThemeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setColorTheme(theme.id)}
          >
            <span className="flex items-center gap-3">
              <ThemeSwatch theme={theme} />
              <span className="text-sm font-medium">{theme.name}</span>
            </span>
            {selected ? (
              <CheckIcon className="size-4 text-primary" />
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

