/** Theme color palette applied as CSS custom properties on the document root. */
export interface ThemeColors {
  /** Page / shell background */
  readonly background: string;
  /** Default text color */
  readonly foreground: string;
  /** Primary accent (buttons, links, focus rings) */
  readonly accent: string;
  /** Sidebar surface */
  readonly sidebar: string;
  /** Editor / main content surface */
  readonly editor: string;
  /** Terminal surface */
  readonly terminal: string;
  /** Status bar surface */
  readonly statusBar: string;
}

export interface Theme {
  /** Unique, kebab-cased identifier persisted in user settings. */
  readonly id: string;
  /** Human-readable display name. */
  readonly name: string;
  /** Semantic color tokens. */
  readonly colors: ThemeColors;
  /** Primary font family stack. */
  readonly fontFamily: string;
  /** Base font size in pixels. */
  readonly fontSize: number;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const SANS_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const t3Dark: Theme = {
  id: "t3-dark",
  name: "T3 Dark",
  colors: {
    background: "#0a0a0b",
    foreground: "#e5e5e5",
    accent: "#6d5cff",
    sidebar: "#111113",
    editor: "#0f0f11",
    terminal: "#0a0a0b",
    statusBar: "#111113",
  },
  fontFamily: SANS_FONT_FAMILY,
  fontSize: 14,
};

const t3Light: Theme = {
  id: "t3-light",
  name: "T3 Light",
  colors: {
    background: "#ffffff",
    foreground: "#1c1c1e",
    accent: "#5046e5",
    sidebar: "#f5f5f7",
    editor: "#ffffff",
    terminal: "#f5f5f7",
    statusBar: "#f0f0f2",
  },
  fontFamily: SANS_FONT_FAMILY,
  fontSize: 14,
};

const t3Midnight: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  colors: {
    background: "#06061a",
    foreground: "#c8c8d8",
    accent: "#7b8cff",
    sidebar: "#0b0b24",
    editor: "#08081e",
    terminal: "#06061a",
    statusBar: "#0b0b24",
  },
  fontFamily: SANS_FONT_FAMILY,
  fontSize: 14,
};

// ---------------------------------------------------------------------------
// Registry helpers
// ---------------------------------------------------------------------------

const BUILT_IN_THEMES: readonly Theme[] = [t3Dark, t3Light, t3Midnight];

const themeById = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

/**
 * Return every built-in theme. The first entry (`t3-dark`) is the default.
 */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/**
 * Look up a theme by `id`. Returns `undefined` when the id is not recognized.
 */
export function getTheme(id: string): Theme | undefined {
  return themeById.get(id);
}

/** The default theme id used when nothing has been persisted yet. */
export const DEFAULT_THEME_ID: string = t3Dark.id;

